module top_module(
    output Y,
    input A1,
    input A2,
    input A3,
    input A4,
    input EN
);wire [3:0] unused_inputs;
    wire and_output;

    // Assign the unused_inputs to a vector
    assign unused_inputs = {A4, A3, A2, A1};

    // Perform AND operation on unused_inputs and include enable
    assign and_output = (EN) ? (unused_inputs[3] & unused_inputs[2] & unused_inputs[1] & unused_inputs[0]) : 1'b0;

    // Assign the result to Y
    assign Y = and_output;

endmodule
